private void xrTableCell7_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    object fObj = GetCurrentColumnValue("FChickRecived");
    object mObj = GetCurrentColumnValue("MChickRecived");

    decimal f = 0;
    decimal m = 0;

    if (fObj != null && fObj != DBNull.Value)
        decimal.TryParse(fObj.ToString(), out f);

    if (mObj != null && mObj != DBNull.Value)
        decimal.TryParse(mObj.ToString(), out m);

    if (f > 0)
    {
        decimal result = (m / f) * 100;
        cell.Text = result.ToString("N2") + "%";
    }
    else
    {
        cell.Text = "0.00"; 
    }
}

