private void xrTableCell25_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Get the current row values as decimals
    decimal chicksReceived = Convert.ToDecimal(GetCurrentColumnValue("FChickRecived"));
    decimal femaleMortWeek = Convert.ToDecimal(GetCurrentColumnValue("Female_Mort_Week"));

    // Calculate percentage safely
    if (chicksReceived > 0)
    {
        decimal percent = (femaleMortWeek / chicksReceived) * 100;
        cell.Text = percent.ToString("0.00") + "%"; // format with 2 decimals
    }
    else
    {
        cell.Text = "0.00"; // or use "" if you want it blank
    }
}

